def get_icon_path(icon_name: str) -> str | None:
    """Return the SVG path for a given icon name, or None if not found."""
    # Normalize name: strip fas:/far:/fab: prefix, lowercase, replace dash/underscore
    name = icon_name.lower().strip()
    # Strip common prefixes
    for prefix in ("fas:", "far:", "fab:", "fa-", "fi-", "icon-"):
        if name.startswith(prefix):
            name = name[len(prefix):]
    # Also handle 'fa ' prefix (Font Awesome class style)
    if name.startswith("fa "):
        name = name[3:]
    return ICON_PATHS.get(name)


def list_icons() -> list[str]:
    """Return a sorted list of all available icon names."""
    return sorted(ICON_PATHS.keys())
